#include <iostream>
#include <thread>
#include <mutex>
#include <vector>
#include <chrono>

// --- Without mutex (race condition!) ---

class UnsafeCounter {
private:
    int value = 0;

public:
    void increment() {
        value++;  // Not thread-safe!
    }

    int getValue() const { return value; }
};

// --- With mutex (thread-safe) ---

class SafeCounter {
private:
    int value = 0;
    mutable std::mutex mtx;  // mutable allows locking in const methods

public:
    void increment() {
        std::lock_guard<std::mutex> lock(mtx);
        value++;
    }

    int getValue() const {
        std::lock_guard<std::mutex> lock(mtx);
        return value;
    }
};

// --- Shared resource with mutex ---

class BankAccount {
private:
    double balance = 0;
    std::mutex mtx;

public:
    void deposit(double amount) {
        std::lock_guard<std::mutex> lock(mtx);
        balance += amount;
        std::cout << "Deposited " << amount << " (Balance: " << balance << ")" << std::endl;
    }

    void withdraw(double amount) {
        std::lock_guard<std::mutex> lock(mtx);
        if (balance >= amount) {
            balance -= amount;
            std::cout << "Withdrew " << amount << " (Balance: " << balance << ")" << std::endl;
        } else {
            std::cout << "Insufficient funds!" << std::endl;
        }
    }

    double getBalance() const {
        std::lock_guard<std::mutex> lock(mtx);
        return balance;
    }
};

// --- Recursive mutex (same thread can lock multiple times) ---

class RecursiveExample {
private:
    std::recursive_mutex recMtx;
    int depth = 0;

public:
    void recursiveFunction(int count) {
        std::lock_guard<std::recursive_mutex> lock(recMtx);
        depth++;
        std::cout << "Depth: " << depth << std::endl;

        if (count > 0) {
            recursiveFunction(count - 1);
        }

        depth--;
    }
};

// --- Timed mutex ---

class TimedExample {
private:
    std::timed_mutex timedMtx;

public:
    bool tryLockFor(int milliseconds) {
        std::chrono::milliseconds timeout(milliseconds);

        if (timedMtx.try_lock_for(timeout)) {
            std::cout << "Lock acquired!" << std::endl;
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
            timedMtx.unlock();
            return true;
        } else {
            std::cout << "Lock timeout!" << std::endl;
            return false;
        }
    }
};

int main() {
    std::cout << "=== Mutexes & Race Conditions ===" << std::endl;

    // 1. Race condition demonstration
    std::cout << "\n--- Race Condition ---" << std::endl;
    UnsafeCounter unsafe;
    std::vector<std::thread> unsafeThreads;

    for (int i = 0; i < 1000; i++) {
        unsafeThreads.push_back(std::thread([&unsafe]() {
            unsafe.increment();
        }));
    }

    for (auto& t : unsafeThreads) t.join();
    std::cout << "Unsafe counter: " << unsafe.getValue() << " (should be 1000)" << std::endl;

    // 2. Mutex fix
    std::cout << "\n--- With Mutex (Thread-safe) ---" << std::endl;
    SafeCounter safe;
    std::vector<std::thread> safeThreads;

    for (int i = 0; i < 1000; i++) {
        safeThreads.push_back(std::thread([&safe]() {
            safe.increment();
        }));
    }

    for (auto& t : safeThreads) t.join();
    std::cout << "Safe counter: " << safe.getValue() << " (should be 1000)" << std::endl;

    // 3. Bank account with mutex
    std::cout << "\n--- Bank Account ---" << std::endl;
    BankAccount account;

    std::vector<std::thread> bankThreads;
    for (int i = 0; i < 5; i++) {
        bankThreads.push_back(std::thread([&account]() {
            account.deposit(10);
            account.withdraw(5);
        }));
    }

    for (auto& t : bankThreads) t.join();
    std::cout << "Final balance: " << account.getBalance() << std::endl;

    // 4. Recursive mutex
    std::cout << "\n--- Recursive Mutex ---" << std::endl;
    RecursiveExample rec;
    rec.recursiveFunction(3);

    // 5. Timed mutex
    std::cout << "\n--- Timed Mutex ---" << std::endl;
    TimedExample timed;
    timed.tryLockFor(500);

    // 6. Lock types
    std::cout << "\n--- Lock Types ---" << std::endl;
    std::cout << "🔹 std::lock_guard — RAII lock (recommended)" << std::endl;
    std::cout << "🔹 std::unique_lock — flexible lock" << std::endl;
    std::cout << "🔹 std::recursive_mutex — same thread can lock multiple times" << std::endl;
    std::cout << "🔹 std::timed_mutex — try to lock with timeout" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <thread>
#include <mutex>

std::mutex mtx;
int data = 0;

int main() {
    std::thread t1([]() {
        mtx.lock();
        data++;
        // Forgot to unlock! Deadlock!
    });

    std::thread t2([]() {
        mtx.lock();  // Will wait forever
        data++;
        mtx.unlock();
    });

    t1.join();
    t2.join();
    return 0;
}

phase2.explanation:
Thread 1 locked the mutex but never unlocked it!

**The fix:**
```cpp
std::thread t1([]() {
    mtx.lock();
    data++;
    mtx.unlock();  // ← Always unlock!
});
```

**Better:** Use `std::lock_guard`:
```cpp
std::thread t1([]() {
    std::lock_guard<std::mutex> lock(mtx);
    data++;  // Auto-unlocked when lock goes out of scope
});
```

**PlusPlus-chan says:**
"Always unlock mutexes. Or better, use `std::lock_guard`."

