#include <iostream>
#include <thread>
#include <mutex>
#include <vector>

class SharedCounter {
private:
    int count = 0;
    std::mutex mtx;

public:
    void increment() {
        std::lock_guard<std::mutex> lock(mtx);
        count++;
    }

    int getValue() const {
        std::lock_guard<std::mutex> lock(mtx);
        return count;
    }
};

int main() {
    std::cout << "=== Shared Counter with Mutex ===" << std::endl;

    SharedCounter counter;
    std::vector<std::thread> threads;

    for (int i = 0; i < 10; i++) {
        threads.push_back(std::thread([&counter]() {
            for (int j = 0; j < 1000; j++) {
                counter.increment();
            }
        }));
    }

    for (auto& t : threads) {
        t.join();
    }

    std::cout << "Final count: " << counter.getValue() << std::endl;
    std::cout << "Expected: 10000" << std::endl;

    return 0;
}
